    public static final class SessionManager {
        private final Map<String, AuthenticatedSession> sessions = new ConcurrentHashMap<>();
        private final byte[] secret;

        public SessionManager(String secret) {
            if (secret == null || secret.isEmpty()) throw new IllegalArgumentException("secret required");
            this.secret = secret.getBytes(StandardCharsets.UTF_8);
        }

        public AuthenticatedSession createSession(SamlAuthenticationResult auth) throws SamlProcessingException {
            Objects.requireNonNull(auth, "auth");
            String rawId = UUID.randomUUID().toString();
            String sessionId = signSessionId(rawId, auth.getSubject());
            AuthenticatedSession session = new AuthenticatedSession(
                    sessionId,
                    auth.getSubject(),
                    auth.getNameId(),
                    auth.getIssuer(),
                    auth.getAudience(),
                    Instant.now(),
                    auth.getAuthnInstant(),
                    auth.getNotBefore(),
                    auth.getNotOnOrAfter(),
                    auth.getAttributes()
            );
            sessions.put(sessionId, session);
            return session;
        }

        public AuthenticatedSession getSession(String sessionId) {
            if (sessionId == null) return null;
            return sessions.get(sessionId);
        }

        public void invalidate(String sessionId) {
            if (sessionId == null) return;
            sessions.remove(sessionId);
        }

        private String signSessionId(String rawId, String subject) throws SamlProcessingException {
            try {
                Mac mac = Mac.getInstance("HmacSHA256");
                mac.init(new SecretKeySpec(secret, "HmacSHA256"));
                String payload = rawId + "|" + (subject == null ? "" : subject);
                byte[] sig = mac.doFinal(payload.getBytes(StandardCharsets.UTF_8));
                return rawId + "." + Base64.getUrlEncoder().withoutPadding().encodeToString(sig);
            } catch (Exception e) {
                throw new SamlProcessingException("Unable to sign session id", e);
            }
        }
    }

