    private static X509Certificate loadCertificateFromKeystore(String keystorePath, String password, String alias) throws Exception {
        KeyStore ks = KeyStore.getInstance(KeyStore.getDefaultType());
        try (java.io.InputStream in = new java.io.FileInputStream(keystorePath)) {
            ks.load(in, password != null ? password.toCharArray() : null);
        }
        if (alias != null && !alias.isEmpty()) {
            java.security.cert.Certificate c = ks.getCertificate(alias);
            if (c == null) throw new IllegalArgumentException("No certificate for alias: " + alias);
            if (!(c instanceof X509Certificate)) throw new IllegalArgumentException("Certificate is not X509: " + alias);
            return (X509Certificate) c;
        }
        Enumeration<String> aliases = ks.aliases();
        while (aliases.hasMoreElements()) {
            String a = aliases.nextElement();
            java.security.cert.Certificate c = ks.getCertificate(a);
            if (c instanceof X509Certificate) return (X509Certificate) c;
        }
        throw new IllegalArgumentException("No X509 certificate found in keystore");
    }
